tests_oauth.03_refresh.json:
{
  "_comment": "Send the refresh token in the request body - we don't verify the exact token we get back because it would make the test unnecessarily brittle",
  "url": "http://127.0.0.1:8080/auth/refresh",
  "method": "post",
  "body": {"refreshToken": "<refresh_token>"},
  "response": {
    "accessToken": "$contains newtoken",
    "expiresIn": 3600
  }
}

tests_readme.01_widget_listing.json:
{
  "_comment": "Widget42 appears in the results — assert only what you care about",
  "url": "/items",
  "match_subsets": true,
  "response": { "results": [{ "name": "Widget42" }] }
}

tests_readme.02_graphql_query.json:
{
  "_comment": "Every post has a named author and at least one tag, comments have text and upvotes, no GraphQL errors",
  "url": "/graphql",
  "method": "post",
  "body": { "query": "{ posts { id title author { name } tags comments { text upvotes replies { text } } reactions } totalCount }" },
  "match_subsets": true,
  "match_every_entry": true,
  "response": {
    "errors": null,
    "data": {
      "posts": [{
        "author": { "name": "$text" },
        "tags": "$len_gt 0",
        "comments": [{
          "text": "$text",
          "replies": [{ "text": "$text" }]
        }],
        "reactions": "$len_gt 0"
      }],
      "totalCount": "$gt 0"
    }
  }
}

tests_readme.03_user_thumbnails.json:
{
  "_comment": "Every user's thumbnail is a live, reachable URL — every image ID is unique",
  "url": "/users/all",
  "match_subsets": true,
  "match_every_entry": true,
  "response": {
    "images": [{ "thumbnail": "$valid_url", "id": "$unique" }]
  }
}

tests_variables.01_store.json:
{
